### Steps to reproduce

1. Place any sample background image within `assets/imgs/bg.png` in a flutter dummy project.
2. Run the provided Code Sample in a simulator (e.g. iPhone 15).
3. Switch among the tabs by clicking on them and tap into the text field -> Keyboard shows up, Background img stays fixed in the bg.
4. On any tab screen, tap on the button `Push To Upper Screen (Normal Push)`. 
5. Tap into the text field in the pushed screen, and you'll see that the background img resizes.
6. Leave that screen and tap the button `Push To Upper Screen (Rootnav Push)`. 
7. Tap into the text field in the pushed screen, and you'll see that the background img DOES NOT resize.

### Expected results

I actually expected the outcome of 5. to be the same as 7. (but with the bottom navigation bar displayed below). I'm unsure if this is actually a bug, as it makes it impossible to use a non-resizing background image in your app as soon as your app uses pushed screens, together with a `CupertinoTabScaffold`?

PS: I'd really prefer to not use `resizeToAvoidBottomInset: false` for obvious UX reasons.

### Actual results

See above.

### Code sample

<details open><summary>Code sample</summary>

```dart
import 'package:flutter/cupertino.dart';
import 'package:flutter/material.dart';

void main() {
  runApp(const MyApp());
}

class MyApp extends StatelessWidget {
  const MyApp({super.key});

  // This widget is the root of your application.
  @override
  Widget build(BuildContext context) {
    return const MaterialApp(
      title: 'Demo',
      home: MyHomePage(),
    );
  }
}

class MyHomePage extends StatefulWidget {
  const MyHomePage({super.key});

  @override
  State<MyHomePage> createState() => _MyHomePageState();
}

class _MyHomePageState extends State<MyHomePage> {
  @override
  Widget build(BuildContext context) {
    /// to be able to use TextFormField within Cupertino
    return ContainerWithBG(
      child: CupertinoTabScaffold(
        backgroundColor: Colors.transparent,
        tabBar: CupertinoTabBar(items: const [
          BottomNavigationBarItem(
            icon: Icon(
              Icons.abc,
            ),
          ),
          BottomNavigationBarItem(
            icon: Icon(
              Icons.adb,
            ),
          ),
        ]),
        tabBuilder: (context, index) {
          return CupertinoTabView(
            builder: (context) {
              return CupertinoPageScaffold(
                backgroundColor: Colors.transparent,
                navigationBar: CupertinoNavigationBar(
                  middle: Text(
                      'Base Tab $index - Img not moving when keyboard toggled'),
                ),
                child: Center(
                  child: Column(
                    mainAxisAlignment: MainAxisAlignment.center,
                    crossAxisAlignment: CrossAxisAlignment.center,
                    children: [
                      Text(
                        'Random Content of Tab $index',
                        style: const TextStyle(
                          color: Colors.white,
                          fontSize: 25,
                        ),
                      ),
                      const SizedBox(
                        height: 30,
                      ),
                      const InputField(),
                      const SizedBox(
                        height: 30,
                      ),
                      ElevatedButton(
                        onPressed: () {
                          Navigator.of(context).push(
                            MaterialPageRoute(
                              builder: (context) => const UpperLayer(
                                triggeredViaRootNav: false,
                              ),
                            ),
                          );
                        },
                        child: const Text(
                          'Push To Upper Screen (Normal Push)',
                        ),
                      ),
                      const SizedBox(
                        height: 30,
                      ),
                      ElevatedButton(
                        onPressed: () {
                          Navigator.of(context, rootNavigator: true).push(
                            MaterialPageRoute(
                              builder: (context) => const UpperLayer(
                                triggeredViaRootNav: true,
                              ),
                            ),
                          );
                        },
                        child: const Text(
                          'Push To Upper Screen (Rootnav Push)',
                        ),
                      ),
                    ],
                  ),
                ),
              );
            },
          );
        },
      ),
    );
  }
}

/// Text Field
class InputField extends StatelessWidget {
  const InputField({super.key});

  @override
  Widget build(BuildContext context) {
    /// Material() wrapper to be able to use TextFormField() within Cupertino
    return Material(
      color: Colors.transparent,
      child: Container(
        color: Colors.white,
        margin: const EdgeInsets.all(25.0),
        child: TextFormField(),
      ),
    );
  }
}

/// BG IMG Decoration
class ContainerWithBG extends StatelessWidget {
  final Widget child;

  const ContainerWithBG({
    super.key,
    required this.child,
  });

  @override
  Widget build(BuildContext context) {
    return Container(
      decoration: const BoxDecoration(
        image: DecorationImage(
          image: AssetImage("assets/imgs/bg.png"),
          fit: BoxFit.cover,
        ),
      ),
      child: child,
    );
  }
}

class UpperLayer extends StatelessWidget {
  /// Just for app bar naming for better understanding
  final bool triggeredViaRootNav;

  const UpperLayer({
    super.key,
    required this.triggeredViaRootNav,
  });

  @override
  Widget build(BuildContext context) {
    return ContainerWithBG(
      child: CupertinoPageScaffold(
        backgroundColor: Colors.transparent,
        navigationBar: CupertinoNavigationBar(
          middle: Text(
            (triggeredViaRootNav
                ? 'Pushed Screen - Img NOT Moving when keyboard toggled (RootNav Push)'
                : 'Pushed Screen - Img Moving when keyboard toggled (Normal Push)'),
          ),
        ),
        child: const Center(
          child: InputField(),
        ),
      ),
    );
  }
}

