The problem is that the `TextController`'s listener is called before the layout has occurred, so the underlying `TextPainter`'s text still holds the old text.

I can think of these workarounds:
- Check if the caret is at the last position; if so, then change its offset to `offset - 1` (this is only needed if the new text length is longer than the old one).
- Update the render object's text (note: this is a hack and might have side effects).
- `WidgetsBinding.instance.addPostFrameCallback`: determine position when text is layed out (_I think this is the best solution unless you need the position at the very moment_)

<details>
<summary>This code updates the render object's text</summary>

```dart
import 'package:flutter/material.dart';

void main() {
  runApp(const MyApp());
}

class MyApp extends StatelessWidget {
  const MyApp({super.key});

  @override
  Widget build(BuildContext context) {
    return const MaterialApp(
      debugShowCheckedModeBanner: false,
      home: MyHomePage(),
    );
  }
}

class MyHomePage extends StatefulWidget {
  const MyHomePage({super.key});

  @override
  _MyHomePageState createState() => _MyHomePageState();
}

class _MyHomePageState extends State<MyHomePage> {
  final _textFieldKey = GlobalKey<State<TextField>>();
  final _textFieldController = TextEditingController();

  @override
  void initState() {
    super.initState();
    _textFieldController.addListener(showCaretPosition);
  }

  Future<void> showCaretPosition() async {
    final editableTextKey = (_textFieldKey.currentState! as TextSelectionGestureDetectorBuilderDelegate).editableTextKey;
    final editableTextState = editableTextKey.currentState!;
    final editableTextRender = editableTextState.renderEditable;

    // update renderer
    final nextText = editableTextState.buildTextSpan();
    editableTextRender.text = nextText;

    final cursorTextPosition = _textFieldController.selection.base;
    final caretRect = editableTextRender.getLocalRectForCaret(cursorTextPosition);

    final editableGlobalPosition = editableTextRender.localToGlobal(Offset.zero);

    final overlayState = Overlay.of(context);
    final overlay = OverlayEntry(
      builder: (context) {
        return Positioned(
          left: editableGlobalPosition.dx + caretRect.left + 2.0,
          top: editableGlobalPosition.dy + caretRect.top,
          child: const Material(
            color: Colors.blueGrey,
            child: Text(
              'Caret',
              style: TextStyle(fontSize: 20),
            ),
          ),
        );
      },
    );
    overlayState.insert(overlay);

    await Future<void>.delayed(const Duration(milliseconds: 500));
    overlay.remove();
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      body: Center(
        child: Padding(
          padding: const EdgeInsets.all(40),
          child: TextField(
            key: _textFieldKey,
            controller: _textFieldController,
            style: const TextStyle(fontSize: 20),
            minLines: 1,
            maxLines: 2,
          ),
        ),
      ),
    );
  }
}

```

